package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.file.Path;

import org.eclipse.rdf4j.benchmark.common.ThemeQueryCatalog;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.util.RDFInserter;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.Timeout;
import org.junit.jupiter.api.io.TempDir;

class LmdbAdaptiveFilterPlacementThemeIT {

	private static final String ADAPTIVE_ENABLED_PROPERTY = "rdf4j.lmdb.adaptiveFilterPlacement.enabled";
	private static final String NATIVE_ENABLED_PROPERTY = "rdf4j.lmdb.nativeQueryEngine.enabled";

	@Test
	@Timeout(60)
	void catalogQueriesRemainCorrectAndAdaptiveMovesByDefaultAfterPlannedObservation(@TempDir Path dataDir) {
		String previousAdaptive = System.getProperty(ADAPTIVE_ENABLED_PROPERTY);
		String previousNative = System.getProperty(NATIVE_ENABLED_PROPERTY);
		System.clearProperty(ADAPTIVE_ENABLED_PROPERTY);
		System.setProperty(NATIVE_ENABLED_PROPERTY, Boolean.TRUE.toString());
		LmdbStore store = new LmdbStore(dataDir.toFile(), ConfigUtil.createConfig().setSketchEstimatorEnabled(false));
		SailRepository repository = new SailRepository(store);
		try {
			repository.init();
			try (var connection = repository.getConnection()) {
				connection.begin(IsolationLevels.NONE);
				ThemeDataSetGenerator.generate(Theme.ADAPTIVE_FILTER_PLACEMENT, new RDFInserter(connection));
				connection.commit();
			}
			repository.shutDown();
			store = new LmdbStore(dataDir.toFile(), ConfigUtil.createConfig().setSketchEstimatorEnabled(false));
			repository = new SailRepository(store);
			repository.init();
			for (int queryIndex = 0; queryIndex < ThemeQueryCatalog.QUERY_COUNT; queryIndex++) {
				String catalogQuery = ThemeQueryCatalog.queryFor(Theme.ADAPTIVE_FILTER_PLACEMENT, queryIndex);
				try (var connection = repository.getConnection();
						TupleQueryResult result = connection.prepareTupleQuery(catalogQuery).evaluate()) {
					long rows = 0L;
					while (result.hasNext()) {
						var bindings = result.next();
						assertNotNull(bindings.getValue("probe"), "query " + queryIndex);
						assertEquals(bindings.getValue("probe"), bindings.getValue("selectedProbe"),
								"query " + queryIndex);
						rows++;
					}
					assertEquals(256L, rows, "query " + queryIndex);
				}
			}

			String query = ThemeQueryCatalog.queryFor(Theme.ADAPTIVE_FILTER_PLACEMENT, 0);
			TupleExpr telemetry;
			Explanation telemetryExplanation;
			try (var connection = repository.getConnection()) {
				telemetryExplanation = connection.prepareTupleQuery(query).explain(Explanation.Level.Telemetry);
				telemetry = (TupleExpr) telemetryExplanation.tupleExpr();
			}
			TupleExpr adaptiveNode = findAdaptiveNode(telemetry);
			assertNotNull(adaptiveNode, () -> "Expected adaptive placement telemetry; explanation="
					+ telemetryExplanation + "; plan=" + telemetry);
			assertEquals(1L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementAdmitted"));
			assertEquals(1L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementPlannedDepth"));
			assertEquals(1L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementInitialDepth"));
			assertEquals(3L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementFinalDepth"));
			assertEquals(16_384L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementPrefixes"));
			assertTrue(adaptiveNode.getLongMetricActual("adaptiveFilterPlacementWindows") > 0L);
			assertEquals(1_024L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementEvaluations"));
			assertEquals(1L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementMoves"));
			assertEquals(1L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementCommits"));
			assertEquals(0L, adaptiveNode.getLongMetricActual("adaptiveFilterPlacementRollbacks"));
			assertEquals("[1, 2, 3]",
					adaptiveNode.getStringMetricActual("adaptiveFilterPlacementCandidateDepths"));
			assertEquals("[16384, 131072, 256]",
					adaptiveNode.getStringMetricActual("adaptiveFilterPlacementCandidateArrivals"));
		} finally {
			repository.shutDown();
			restoreProperty(ADAPTIVE_ENABLED_PROPERTY, previousAdaptive);
			restoreProperty(NATIVE_ENABLED_PROPERTY, previousNative);
		}
	}

	private static TupleExpr findAdaptiveNode(TupleExpr root) {
		TupleExpr[] found = new TupleExpr[1];
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(org.eclipse.rdf4j.query.algebra.QueryModelNode node) {
				if (found[0] == null && node instanceof TupleExpr tupleExpr
						&& tupleExpr.getLongMetricActual("adaptiveFilterPlacementAdmitted") == 1L) {
					found[0] = tupleExpr;
				}
				super.meetNode(node);
			}
		});
		return found[0];
	}

	private static void restoreProperty(String property, String previous) {
		if (previous == null) {
			System.clearProperty(property);
		} else {
			System.setProperty(property, previous);
		}
	}
}
